sql:
SELECT diagnosis_name
FROM diagnoses
WHERE diagnosis_id = 1001;

SELECT diagnosis_id_2
FROM diagnosis_relations
WHERE confidence_score > 0.8;

SELECT diagnosis_name, icd_code, IFNULL(description, 'No description available') AS description
FROM diagnoses
WHERE icd_code LIKE 'J%' AND diagnosis_id < 1000;

external_knowledge:
Severe respiratory issues: Respiratory_tract_infection;
Septic shock: A life-threatening condition that occurs when sepsis leads to a drastic drop in blood pressure;
Highly likely relation: Confidence score > 0.75;
Fatal outcome: Target outcome is 'Death'.

